svg.script:

      function teleportToPoint(evt) {
        const element = evt.currentTarget;           // the clicked circle
        const desc = element.querySelector('desc');  // or element.getElementsByTagName('desc')[0]

        if (!desc) {
          alert("No description found on this point");
          return;
        }

        const descText = desc.textContent.trim();

        // Simple key=value parser (you can improve it later)
        const data = {};
        descText.split(/\s+/).forEach(pair => {
          const [key, value] = pair.split('=');
          if (key && value !== undefined) {
            data[key.trim()] = value.trim();
          }
        });

        const { scene, x, y, z } = data;

        if (!scene || !x || !y || !z) {
          alert("Incomplete teleport data in description");
          return;
        }

        const url = `http://localhost:${window.teleportPort || 8080}/teleport?scene=${encodeURIComponent(scene)}&x=${x}&y=${y}&z=${z}`;

		// alert(`Teleporting to scene=${scene} x=${x} y=${y} z=${z}`);

        fetch(url)
          .then(response => {
            if (!response.ok) {
              return response.text().then(text => { throw new Error(text); });
            }
            return response.text();
          })
          .then(text => alert('Success: ' + text))
          .catch(err => alert('Teleport failed: ' + err.message));
      }
